const ethers = require('ethers');

const ERC20_ABI = [
  'function name() view returns (string)',
  'function symbol() view returns (string)',
  'function decimals() view returns (uint8)',
  'function balanceOf(address) view returns (uint256)',
  'function allowance(address owner, address spender) view returns (uint256)',
  'function approve(address spender, uint256 amount) returns (bool)',
  'function transfer(address to, uint256 amount) returns (bool)',
  'event Approval(address indexed owner, address indexed spender, uint256 value)',
  'event Transfer(address indexed from, address indexed to, uint256 value)'
];

const DEX_ABI = [
  'function swapExactTokensForTokens(uint256 amountIn, uint256 amountOutMin, address[] calldata path, address to, uint256 deadline) returns (uint256[] memory amounts)',
  'function swapTokensForExactTokens(uint256 amountOut, uint256 amountInMax, address[] calldata path, address to, uint256 deadline) returns (uint256[] memory amounts)',
  'function getAmountsOut(uint256 amountIn, address[] calldata path) view returns (uint256[] memory amounts)',
  'function getAmountsIn(uint256 amountOut, address[] calldata path) view returns (uint256[] memory amounts)',
  'event Swap(address indexed sender, uint256 amount0In, uint256 amount1In, uint256 amount0Out, uint256 amount1Out, address indexed to)'
];

class TokenSwapDApp {
  constructor(dexAddress, providerUrl) {
    this.dexAddress = dexAddress;
    this.provider = new ethers.JsonRpcProvider(providerUrl);
    this.signer = null;
    this.dexContract = null;
    this.MAX_UINT256 = ethers.MaxUint256;
  }

  async connectWallet() {
    if (typeof window.ethereum !== 'undefined') {
      await window.ethereum.request({ method: 'eth_requestAccounts' });
      this.provider = new ethers.BrowserProvider(window.ethereum);
      this.signer = await this.provider.getSigner();
      this.dexContract = new ethers.Contract(this.dexAddress, DEX_ABI, this.signer);
      return await this.signer.getAddress();
    } else {
      throw new Error('MetaMask not installed');
    }
  }

  async getTokenContract(tokenAddress) {
    if (!this.signer) {
      throw new Error('Wallet not connected');
    }
    return new ethers.Contract(tokenAddress, ERC20_ABI, this.signer);
  }

  async getTokenInfo(tokenAddress) {
    const tokenContract = new ethers.Contract(tokenAddress, ERC20_ABI, this.provider);
    const [name, symbol, decimals] = await Promise.all([
      tokenContract.name(),
      tokenContract.symbol(),
      tokenContract.decimals()
    ]);
    return { name, symbol, decimals, address: tokenAddress };
  }

  async getTokenBalance(tokenAddress, userAddress) {
    const tokenContract = new ethers.Contract(tokenAddress, ERC20_ABI, this.provider);
    const balance = await tokenContract.balanceOf(userAddress);
    const decimals = await tokenContract.decimals();
    return {
      raw: balance,
      formatted: ethers.formatUnits(balance, decimals)
    };
  }

  async checkAllowance(tokenAddress, ownerAddress) {
    const tokenContract = new ethers.Contract(tokenAddress, ERC20_ABI, this.provider);
    const allowance = await tokenContract.allowance(ownerAddress, this.dexAddress);
    return allowance;
  }

  async approveToken(tokenAddress, amount = null) {
    if (!this.signer) {
      throw new Error('Wallet not connected');
    }

    const tokenContract = await this.getTokenContract(tokenAddress);
    const approvalAmount = amount || this.MAX_UINT256;
    
    const tx = await tokenContract.approve(this.dexAddress, approvalAmount);
    console.log('Approval transaction sent:', tx.hash);
    
    const receipt = await tx.wait();
    console.log('Approval confirmed:', receipt.hash);
    
    return receipt;
  }

  async approveMaxAmount(tokenAddress) {
    return await this.approveToken(tokenAddress, this.MAX_UINT256);
  }

  async ensureApproval(tokenAddress, requiredAmount) {
    const userAddress = await this.signer.getAddress();
    const currentAllowance = await this.checkAllowance(tokenAddress, userAddress);
    
    if (currentAllowance < requiredAmount) {
      console.log('Insufficient allowance, requesting approval...');
      return await this.approveMaxAmount(tokenAddress);
    }
    
    console.log('Sufficient allowance already exists');
    return null;
  }

  async getAmountsOut(amountIn, path) {
    if (!this.dexContract) {
      this.dexContract = new ethers.Contract(this.dexAddress, DEX_ABI, this.provider);
    }
    
    const amounts = await this.dexContract.getAmountsOut(amountIn, path);
    return amounts;
  }

  async getAmountsIn(amountOut, path) {
    if (!this.dexContract) {
      this.dexContract = new ethers.Contract(this.dexAddress, DEX_ABI, this.provider);
    }
    
    const amounts = await this.dexContract.getAmountsIn(amountOut, path);
    return amounts;
  }

  async swapExactTokensForTokens(amountIn, amountOutMin, tokenInAddress, tokenOutAddress, slippageTolerance = 0.5) {
    if (!this.signer) {
      throw new Error('Wallet not connected');
    }

    const userAddress = await this.signer.getAddress();
    const path = [tokenInAddress, tokenOutAddress];
    
    await this.ensureApproval(tokenInAddress, amountIn);
    
    const amounts = await this.getAmountsOut(amountIn, path);
    const expectedAmountOut = amounts[amounts.length - 1];
    
    const slippageMultiplier = BigInt(Math.floor((100 - slippageTolerance) * 100));
    const calculatedMinAmount = (expectedAmountOut * slippageMultiplier) / BigInt(10000);
    
    const finalMinAmount = amountOutMin > calculatedMinAmount ? amountOutMin : calculatedMinAmount;
    
    const deadline = Math.floor(Date.now() / 1000) + 60 * 20;
    
    const tx = await this.dexContract.swapExactTokensForTokens(
      amountIn,
      finalMinAmount,
      path,
      userAddress,
      deadline
    );
    
    console.log('Swap transaction sent:', tx.hash);
    const receipt = await tx.wait();
    console.log('Swap confirmed:', receipt.hash);
    
    return {
      receipt,
      expectedAmountOut: ethers.formatUnits(expectedAmountOut, 18),
      minAmountOut: ethers.formatUnits(finalMinAmount, 18)
    };
  }

  async swapTokensForExactTokens(amountOut, amountInMax, tokenInAddress, tokenOutAddress, slippageTolerance = 0.5) {
    if (!this.signer) {
      throw new Error('Wallet not connected');
    }

    const userAddress = await this.signer.getAddress();
    const path = [tokenInAddress, tokenOutAddress];
    
    const amounts = await this.getAmountsIn(amountOut, path);
    const expectedAmountIn = amounts[0];
    
    const slippageMultiplier = BigInt(Math.floor((100 + slippageTolerance) * 100));
    const calculatedMaxAmount = (expectedAmountIn * slippageMultiplier) / BigInt(10000);
    
    const finalMaxAmount = amountInMax < calculatedMaxAmount ? amountInMax : calculatedMaxAmount;
    
    await this.ensureApproval(tokenInAddress, finalMaxAmount);
    
    const deadline = Math.floor(Date.now() / 1000) + 60 * 20;
    
    const tx = await this.dexContract.swapTokensForExactTokens(
      amountOut,
      finalMaxAmount,
      path,
      userAddress,
      deadline
    );
    
    console.log('Swap transaction sent:', tx.hash);
    const receipt = await tx.wait();
    console.log('Swap confirmed:', receipt.hash);
    
    return {
      receipt,
      expectedAmountIn: ethers.formatUnits(expectedAmountIn, 18),
      maxAmountIn: ethers.formatUnits(finalMaxAmount, 18)
    };
  }

  async getSwapQuote(amountIn, tokenInAddress, tokenOutAddress) {
    const path = [tokenInAddress, tokenOutAddress];
    const amounts = await this.getAmountsOut(amountIn, path);
    
    const tokenInInfo = await this.getTokenInfo(tokenInAddress);
    const tokenOutInfo = await this.getTokenInfo(tokenOutAddress);
    
    return {
      amountIn: ethers.formatUnits(amountIn, tokenInInfo.decimals),
      amountOut: ethers.formatUnits(amounts[amounts.length - 1], tokenOutInfo.decimals),
      path,
      tokenIn: tokenInInfo,
      tokenOut: tokenOutInfo
    };
  }

  async executeSwap(amountIn, tokenInAddress, tokenOutAddress, slippageTolerance = 0.5) {
    const tokenInContract = await this.getTokenContract(tokenInAddress);
    const decimals = await tokenInContract.decimals();
    const amountInWei = ethers.parseUnits(amountIn.toString(), decimals);
    
    return await this.swapExactTokensForTokens(
      amountInWei,
      0n,
      tokenInAddress,
      tokenOutAddress,
      slippageTolerance
    );
  }

  async batchApprove(tokenAddresses) {
    const results = [];
    for (const tokenAddress of tokenAddresses) {
      try {
        const receipt = await this.approveMaxAmount(tokenAddress);
        results.push({ tokenAddress, success: true, receipt });
      } catch (error) {
        results.push({ tokenAddress, success: false, error: error.message });
      }
    }
    return results;
  }

  async getMultipleBalances(tokenAddresses, userAddress) {
    const balances = {};
    for (const tokenAddress of tokenAddresses) {
      const balance = await this.getTokenBalance(tokenAddress, userAddress);
      const info = await this.getTokenInfo(tokenAddress);
      balances[tokenAddress] = {
        ...balance,
        ...info
      };
    }
    return balances;
  }

  async estimateGas(amountIn, tokenInAddress, tokenOutAddress) {
    if (!this.signer) {
      throw new Error('Wallet not connected');
    }

    const userAddress = await this.signer.getAddress();
    const path = [tokenInAddress, tokenOutAddress];
    const deadline = Math.floor(Date.now() / 1000) + 60 * 20;
    
    const gasEstimate = await this.dexContract.swapExactTokensForTokens.estimateGas(
      amountIn,
      0n,
      path,
      userAddress,
      deadline
    );
    
    return gasEstimate;
  }
}

